-- ============================================================
-- 029_audit_events.sql
-- ============================================================
-- yorgos.ai Audit Events
-- Append-only audit log of meaningful actions taken in the system.
-- Rows are written by trusted server API routes using the service role only.
--
-- RLS is enabled with NO authenticated/anon policies: only the service role
-- (which bypasses RLS) may read or write this table. This matches the pattern
-- used by provider_webhook_events (003) and the token tables (005/008/009).
--
-- Idempotent: CREATE TABLE IF NOT EXISTS and CREATE INDEX IF NOT EXISTS.
-- business_id and actor_user_id are nullable and intentionally have NO foreign
-- key constraints, so audit rows survive deletion of the business or user they
-- reference (audit trails must outlive the entities they describe).

CREATE TABLE IF NOT EXISTS public.audit_events (
  id            uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  business_id   uuid,
  actor_user_id uuid,
  action        text        NOT NULL,
  entity_type   text,
  entity_id     text,
  metadata      jsonb,
  created_at    timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS audit_events_business_created_desc_idx
  ON public.audit_events (business_id, created_at DESC);

-- ---------------------------------------------------------------------------
-- Row Level Security
-- ---------------------------------------------------------------------------
-- RLS enabled, no public policies. Service role bypasses RLS and is the only
-- principal that can read or write audit events.

ALTER TABLE public.audit_events ENABLE ROW LEVEL SECURITY;

-- (No policies created for audit_events by design.)

-- ---------------------------------------------------------------------------
-- Grants
-- ---------------------------------------------------------------------------
-- No grants to anon or authenticated. Service role only.

REVOKE ALL PRIVILEGES ON TABLE public.audit_events FROM anon;
REVOKE ALL PRIVILEGES ON TABLE public.audit_events FROM authenticated;
REVOKE ALL PRIVILEGES ON TABLE public.audit_events FROM service_role;

GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.audit_events TO service_role;

-- ============================================================
-- 030_jobs.sql
-- ============================================================
-- yorgos.ai Jobs Queue
-- Generic table backing a future asynchronous job queue (e.g. deferred email
-- sends, webhook retries, scheduled follow-ups). A worker process polls for
-- pending rows whose run_at is due, ordered by run_at.
--
-- Not yet wired to any worker; this migration only provisions the schema.
-- Rows are written and claimed exclusively by server-side code using the
-- service role. RLS is enabled with no public policies (service role bypasses
-- RLS), consistent with provider_webhook_events (003) and audit_events (029).
--
-- Idempotent: CREATE TABLE IF NOT EXISTS and CREATE INDEX IF NOT EXISTS.
-- business_id is nullable with no FK so system-level jobs (not tied to a
-- tenant) can be enqueued. updated_at is managed by the API/worker layer, not
-- by a trigger, consistent with the rest of the schema.

CREATE TABLE IF NOT EXISTS public.jobs (
  id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  business_id uuid,
  type        text,
  payload     jsonb,
  status      text        NOT NULL DEFAULT 'pending',
  attempts    integer     NOT NULL DEFAULT 0,
  run_at      timestamptz NOT NULL DEFAULT now(),
  created_at  timestamptz NOT NULL DEFAULT now(),
  updated_at  timestamptz NOT NULL DEFAULT now()
);

-- Worker dispatch index: find due pending jobs (filter status, order by run_at).
CREATE INDEX IF NOT EXISTS jobs_status_run_at_idx
  ON public.jobs (status, run_at);

-- ---------------------------------------------------------------------------
-- Row Level Security
-- ---------------------------------------------------------------------------
-- RLS enabled, no public policies. Service role bypasses RLS and is the only
-- principal that enqueues, claims, or completes jobs.

ALTER TABLE public.jobs ENABLE ROW LEVEL SECURITY;

-- (No policies created for jobs by design.)

-- ---------------------------------------------------------------------------
-- Grants
-- ---------------------------------------------------------------------------
-- No grants to anon or authenticated. Service role only.

REVOKE ALL PRIVILEGES ON TABLE public.jobs FROM anon;
REVOKE ALL PRIVILEGES ON TABLE public.jobs FROM authenticated;
REVOKE ALL PRIVILEGES ON TABLE public.jobs FROM service_role;

GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.jobs TO service_role;

-- ============================================================
-- 031_per_user_sip_provisioning.sql
-- ============================================================
-- Migration 031: Per-user SIP provisioning + telephony onboarding mode + presence.
--
-- Additive and idempotent (ADD COLUMN IF NOT EXISTS / CREATE TABLE IF NOT EXISTS /
-- DROP POLICY IF EXISTS). No drops or renames. Safe to re-run.
--
-- Context: the browser phone currently authenticates every user with a single
-- shared SIP account from env (PHONE_SIP_*). This migration gives each business
-- its OWN browser SIP credential and adds the multi-user telephony scaffolding:
--   1) browser_sip_endpoints.sip_password_enc — per-business SIP password,
--      AES-256-GCM encrypted by the app (env SIP_CRED_ENC_KEY). The DB never
--      stores plaintext. The matching credential reaches Asterisk via the sync
--      described in docs/ASTERISK_REALTIME_PROVISIONING.md.
--   2) businesses.telephony_mode — the A/B onboarding model for the user's
--      existing number ('forward' = keep own number + divert; 'native' = use
--      the assigned Opiflow number only).
--   3) business_user_presence — per-user availability used by call routing
--      (ring the app vs. send to AI intake / voicemail).
--
-- The app reads all of these DEFENSIVELY: if this migration has not yet been
-- applied, the relevant endpoints degrade gracefully and the existing shared-env
-- phone path keeps working unchanged.

-- ---------------------------------------------------------------------------
-- 1) Per-user SIP credential storage
-- ---------------------------------------------------------------------------
ALTER TABLE public.browser_sip_endpoints
  ADD COLUMN IF NOT EXISTS sip_password_enc    text,
  ADD COLUMN IF NOT EXISTS sip_password_set_at timestamptz;

-- ---------------------------------------------------------------------------
-- 2) Telephony onboarding model on the business
--    'native'  = Model B: use the assigned Opiflow number only.
--    'forward' = Model A: keep own number, forward (divert) it to the Opiflow number.
-- ---------------------------------------------------------------------------
ALTER TABLE public.businesses
  ADD COLUMN IF NOT EXISTS telephony_mode           text,
  ADD COLUMN IF NOT EXISTS forwarding_source_number text;

DO $$
BEGIN
  ALTER TABLE public.businesses
    ADD CONSTRAINT businesses_telephony_mode_check
    CHECK (telephony_mode IS NULL OR telephony_mode IN ('native', 'forward'));
EXCEPTION
  WHEN duplicate_object THEN NULL;
END $$;

-- ---------------------------------------------------------------------------
-- 3) Per-user presence
-- ---------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.business_user_presence (
  user_id     uuid        NOT NULL REFERENCES auth.users(id)       ON DELETE CASCADE,
  business_id uuid        NOT NULL REFERENCES public.businesses(id) ON DELETE CASCADE,
  status      text        NOT NULL DEFAULT 'available',
  updated_at  timestamptz NOT NULL DEFAULT now(),
  PRIMARY KEY (user_id, business_id),
  CONSTRAINT business_user_presence_status_check
    CHECK (status IN ('available', 'busy', 'away', 'offline', 'dnd'))
);

CREATE INDEX IF NOT EXISTS business_user_presence_business_id_idx
  ON public.business_user_presence (business_id);

ALTER TABLE public.business_user_presence ENABLE ROW LEVEL SECURITY;

-- Users may read their own presence row; all writes go through the backend
-- (service_role), so no authenticated INSERT/UPDATE policy is granted.
DROP POLICY IF EXISTS "business_user_presence_select_own" ON public.business_user_presence;
CREATE POLICY "business_user_presence_select_own"
  ON public.business_user_presence
  FOR SELECT
  TO authenticated
  USING (user_id = auth.uid());

REVOKE ALL PRIVILEGES ON TABLE public.business_user_presence FROM anon;
GRANT SELECT                         ON TABLE public.business_user_presence TO authenticated;
GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.business_user_presence TO service_role;

-- ============================================================
-- 032_device_push_tokens.sql
-- ============================================================
-- Migration 032: Device push-notification tokens (native app — Android/iOS).
--
-- Additive and idempotent (CREATE TABLE / INDEX / POLICY IF NOT EXISTS,
-- DROP POLICY IF EXISTS). No drops or renames. Safe to re-run.
--
-- Context: the Capacitor native wrapper registers each install for push
-- notifications and POSTs its FCM/APNs token to /api/push/register. The server
-- stores it here (one row per device token) so it can notify the business owner
-- when a customer responds to an offer / appointment, a new call comes in, etc.
--
-- All writes go through the backend (service_role) after the bearer token is
-- verified. A user may READ their own tokens; everything else is denied to anon.
-- The whole feature is INERT until the FCM service-account env is configured on
-- the server — this table simply collects tokens harmlessly in the meantime.

CREATE TABLE IF NOT EXISTS public.device_push_tokens (
  id           uuid        NOT NULL DEFAULT gen_random_uuid(),
  business_id  uuid        NOT NULL REFERENCES public.businesses(id) ON DELETE CASCADE,
  user_id      uuid        NOT NULL REFERENCES auth.users(id)        ON DELETE CASCADE,
  token        text        NOT NULL,
  platform     text        NOT NULL,
  created_at   timestamptz NOT NULL DEFAULT now(),
  last_seen_at timestamptz NOT NULL DEFAULT now(),
  PRIMARY KEY (id),
  CONSTRAINT device_push_tokens_token_key UNIQUE (token),
  CONSTRAINT device_push_tokens_platform_check
    CHECK (platform IN ('android', 'ios', 'web'))
);

CREATE INDEX IF NOT EXISTS device_push_tokens_business_id_idx
  ON public.device_push_tokens (business_id);

CREATE INDEX IF NOT EXISTS device_push_tokens_user_id_idx
  ON public.device_push_tokens (user_id);

ALTER TABLE public.device_push_tokens ENABLE ROW LEVEL SECURITY;

-- Users may read their own device tokens (e.g. to show "this device is
-- registered"). All writes go through the backend (service_role).
DROP POLICY IF EXISTS "device_push_tokens_select_own" ON public.device_push_tokens;
CREATE POLICY "device_push_tokens_select_own"
  ON public.device_push_tokens
  FOR SELECT
  TO authenticated
  USING (user_id = auth.uid());

REVOKE ALL PRIVILEGES ON TABLE public.device_push_tokens FROM anon;
GRANT SELECT                         ON TABLE public.device_push_tokens TO authenticated;
GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.device_push_tokens TO service_role;

-- ============================================================
-- 033_business_invites.sql
-- ============================================================
-- Migration 033: Team invitations (multi-user per business).
--
-- Additive and idempotent. Safe to re-run.
--
-- Context: a business owner/admin invites a teammate by email. We store a
-- pending invite keyed by a hashed token (the raw token goes in the /join/<token>
-- link the owner sends). When the invited person logs in and opens the link, the
-- backend matches their email to the invite and creates a business_users
-- membership (role 'admin' | 'member'). Access then flows through the
-- membership-aware authenticateBusinessRequest (resolveBusinessContext).
--
-- business_users already exists (migration 001) with (business_id, user_id, role,
-- invited_at, accepted_at) — this table only tracks invites BEFORE the invitee
-- has accepted (and possibly before they even have an account).

CREATE TABLE IF NOT EXISTS public.business_invites (
  id          uuid        NOT NULL DEFAULT gen_random_uuid(),
  business_id uuid        NOT NULL REFERENCES public.businesses(id) ON DELETE CASCADE,
  email       text        NOT NULL,
  role        text        NOT NULL DEFAULT 'member',
  token_hash  text        NOT NULL,
  status      text        NOT NULL DEFAULT 'pending',
  invited_by  uuid        REFERENCES auth.users(id) ON DELETE SET NULL,
  created_at  timestamptz NOT NULL DEFAULT now(),
  accepted_at timestamptz,
  expires_at  timestamptz NOT NULL DEFAULT (now() + interval '14 days'),
  PRIMARY KEY (id),
  CONSTRAINT business_invites_token_hash_key UNIQUE (token_hash),
  CONSTRAINT business_invites_role_check   CHECK (role   IN ('admin', 'member')),
  CONSTRAINT business_invites_status_check CHECK (status IN ('pending', 'accepted', 'revoked'))
);

CREATE INDEX IF NOT EXISTS business_invites_business_id_idx ON public.business_invites (business_id);
CREATE INDEX IF NOT EXISTS business_invites_email_idx       ON public.business_invites (lower(email));

ALTER TABLE public.business_invites ENABLE ROW LEVEL SECURITY;

-- All access goes through the backend (service_role). No anon/authenticated grants.
REVOKE ALL PRIVILEGES ON TABLE public.business_invites FROM anon;
REVOKE ALL PRIVILEGES ON TABLE public.business_invites FROM authenticated;
GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.business_invites TO service_role;

-- ============================================================
-- 034_rls_defense_in_depth.sql
-- ============================================================
-- Migration 034: RLS defense-in-depth on service-only tables.
--
-- Additive and idempotent. Safe to re-run.
--
-- Context: the app accesses all business data through the SERVICE-ROLE client,
-- which BYPASSES Row Level Security — tenant isolation is enforced in code via a
-- per-route `.eq('business_id', ...)` filter. That works, but leaves no DB-level
-- safety net. This migration ENABLES RLS on the remaining service-only tables
-- (028 already did customers/communications/offers/tasks; 031/032/033 enabled it
-- on their own tables). With RLS enabled and NO anon/authenticated policy, those
-- keys are denied direct table access, while the service_role STILL bypasses RLS —
-- so the application is completely unaffected. This is pure defense-in-depth: if
-- the anon key ever leaked, it could not read these tables directly.
--
-- We intentionally do NOT touch package_plans / voucher_codes (potential public
-- reads) or businesses / business_users (auth-critical, policy-managed elsewhere).

DO $$
DECLARE
  t text;
  tables text[] := ARRAY[
    'offer_items',
    'offer_response_tokens',
    'appointment_response_tokens',
    'customer_intake_tokens',
    'customer_upload_sessions',
    'customer_upload_tokens',
    'viber_messages',
    'audit_events',
    'jobs',
    'business_phone_numbers',
    'business_phone_number_assignment_history',
    'browser_sip_endpoints',
    'business_subscriptions',
    'phone_number_requests',
    'provider_webhook_events',
    'managed_phone_numbers',
    'voucher_redemptions'
  ];
BEGIN
  FOREACH t IN ARRAY tables LOOP
    IF EXISTS (
      SELECT 1 FROM information_schema.tables
      WHERE table_schema = 'public' AND table_name = t
    ) THEN
      EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY', t);
      -- Deny the anon key outright (service_role bypasses RLS regardless).
      EXECUTE format('REVOKE ALL PRIVILEGES ON TABLE public.%I FROM anon', t);
    END IF;
  END LOOP;
END $$;

-- ============================================================
-- 035_preferred_channel_and_intake_reminder.sql
-- ============================================================
-- Migration 035: Preferred contact channel expansion + intake reminder bookkeeping.
--
-- Two additive, idempotent changes. Safe to re-run on a live table.
-- Applied MANUALLY via the Supabase SQL editor (do not `supabase db push`).
--
-- 1. customers.preferred_contact_method:
--    The original CHECK constraint (customers_preferred_contact_method_check,
--    defined in 003_crm_core.sql) only allowed ('viber', 'email', 'phone').
--    This widens it to also allow 'whatsapp' and 'sms' so the per-customer
--    preferred channel can target those messaging apps. The column DEFAULT
--    stays 'phone' and the column stays NOT NULL — only the allowed value set
--    grows, so every existing row remains valid. We DROP IF EXISTS then ADD,
--    keeping the same constraint name, which makes the change re-runnable.
--
-- 2. customer_intake_tokens reminder bookkeeping:
--    Adds reminder_sent_at (when the intake reminder was last sent) and
--    reminder_count (how many reminders have been sent, default 0) so the
--    reminder pipeline can track follow-ups. Both use ADD COLUMN IF NOT EXISTS.
--    No indexes, RLS, or grant changes needed — service_role already has full
--    access to this table (see 005_customer_intake_tokens.sql).

-- ---------------------------------------------------------------------------
-- 1. Widen customers.preferred_contact_method CHECK constraint
-- ---------------------------------------------------------------------------

ALTER TABLE public.customers
  DROP CONSTRAINT IF EXISTS customers_preferred_contact_method_check;

ALTER TABLE public.customers
  ADD CONSTRAINT customers_preferred_contact_method_check
    CHECK (preferred_contact_method IN ('viber', 'whatsapp', 'sms', 'email', 'phone'));

-- ---------------------------------------------------------------------------
-- 2. Intake reminder bookkeeping columns
-- ---------------------------------------------------------------------------

ALTER TABLE public.customer_intake_tokens
  ADD COLUMN IF NOT EXISTS reminder_sent_at timestamptz,
  ADD COLUMN IF NOT EXISTS reminder_count   int NOT NULL DEFAULT 0;

-- ============================================================
-- 036_email_channel_and_outbound_timeline.sql
-- ============================================================
-- Migration 036: Email as a first-class send channel + outbound-message timeline.
--
-- All changes are additive and idempotent. Safe to re-run on a live database.
-- Applied MANUALLY via the Supabase SQL editor (do NOT `supabase db push`).
--
-- Background
-- ----------
-- B3 ships two related features:
--   #56  Email delivery for intake / upload / appointment links (reuses the
--        Resend send path). The link routes now record sent_channel = 'email'
--        on the corresponding token when an email send succeeds.
--   #57  Outbound messages (Viber / SMS / email) are logged to the existing
--        `communications` table so they appear in the customer timeline, and
--        the Apifon status webhook propagates delivery/seen/failed status onto
--        the linked communications row.
--
-- This migration only widens two CHECK constraints so the token rows can store
-- 'email'. Everything else (communications insert, viber_messages insert,
-- status propagation) uses columns that already exist:
--   * communications  (003_crm_core.sql) already allows channel
--       IN ('call','sms','viber','email') and status
--       IN ('started','sent','delivered','seen','failed','completed').
--   * viber_messages   (006_viber_messages.sql) already has communication_id,
--       provider_request_id, provider_message_id, reference_id, status, etc.
-- so NO schema change is required for the timeline itself — only the two
-- token tables below need 'email' added to their sent_channel domain.
--
-- The application is written to degrade gracefully if this migration has not
-- been applied yet: the token "mark sent" updates are best-effort/swallowed, so
-- email still sends and still appears in the timeline even before 036 runs.
-- This migration simply makes the token's recorded channel accurate.

-- ---------------------------------------------------------------------------
-- 1. customer_intake_tokens.sent_channel  → allow 'email'
-- ---------------------------------------------------------------------------
-- Drop ANY existing CHECK constraint that references sent_channel (its name may
-- differ across environments), then add a single permissive, NULL-safe one.

DO $$
DECLARE c text;
BEGIN
  FOR c IN
    SELECT conname FROM pg_constraint
    WHERE conrelid = 'public.customer_intake_tokens'::regclass
      AND contype = 'c'
      AND pg_get_constraintdef(oid) ILIKE '%sent_channel%'
  LOOP
    EXECUTE 'ALTER TABLE public.customer_intake_tokens DROP CONSTRAINT ' || quote_ident(c);
  END LOOP;
END $$;

ALTER TABLE public.customer_intake_tokens
  ADD CONSTRAINT customer_intake_tokens_sent_channel_check
  CHECK (sent_channel IS NULL OR sent_channel IN ('viber', 'sms', 'email', 'manual'));

-- ---------------------------------------------------------------------------
-- 2. customer_upload_tokens.sent_channel  → allow 'email'
-- ---------------------------------------------------------------------------

DO $$
DECLARE c text;
BEGIN
  FOR c IN
    SELECT conname FROM pg_constraint
    WHERE conrelid = 'public.customer_upload_tokens'::regclass
      AND contype = 'c'
      AND pg_get_constraintdef(oid) ILIKE '%sent_channel%'
  LOOP
    EXECUTE 'ALTER TABLE public.customer_upload_tokens DROP CONSTRAINT ' || quote_ident(c);
  END LOOP;
END $$;

ALTER TABLE public.customer_upload_tokens
  ADD CONSTRAINT customer_upload_tokens_sent_channel_check
  CHECK (sent_channel IS NULL OR sent_channel IN ('viber', 'sms', 'email', 'manual'));

-- appointment_response_tokens.sent_channel already includes 'email'
-- (see 0xx_appointment_response_tokens.sql) — no change needed there.

-- ============================================================
-- 037_appointment_duration.sql
-- ============================================================
-- Migration 037: Appointment duration (start/end) for the day-view calendar.
--
-- Applied MANUALLY via the Supabase SQL editor (do not `supabase db push`).
-- Additive + idempotent. Safe to re-run.
--
-- Appointments are public.tasks rows with type IN ('book_appointment','visit_customer').
-- Today they carry only due_date (date) + due_time (HH:MM text) — no start/end, so the
-- redesign's day-view calendar cannot place them in time-slots with a duration.
-- This adds start_at / end_at (timestamptz) and backfills start_at from (due_date+due_time).
-- due_date / due_time are kept for backward-compat (existing readers/writers still work).

-- 1. tasks: start_at / end_at -------------------------------------------------
ALTER TABLE public.tasks
  ADD COLUMN IF NOT EXISTS start_at timestamptz,
  ADD COLUMN IF NOT EXISTS end_at   timestamptz;

-- end must be after start when both present (idempotent add).
DO $$ BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.table_constraints
    WHERE constraint_name = 'tasks_end_after_start' AND table_schema = 'public' AND table_name = 'tasks'
  ) THEN
    ALTER TABLE public.tasks
      ADD CONSTRAINT tasks_end_after_start CHECK (end_at IS NULL OR start_at IS NULL OR end_at > start_at);
  END IF;
END $$;

-- Backfill start_at from (due_date + due_time) for appointment-type tasks only.
UPDATE public.tasks
   SET start_at = (due_date::text || ' ' || COALESCE(due_time, '09:00') || ':00')::timestamptz
 WHERE type IN ('book_appointment', 'visit_customer')
   AND start_at IS NULL
   AND due_date IS NOT NULL;

-- Partial index powering the day-view calendar popup (business + start, appts only).
CREATE INDEX IF NOT EXISTS tasks_business_start_appt_idx
  ON public.tasks (business_id, start_at)
  WHERE type IN ('book_appointment', 'visit_customer');

-- 2. appointment_response_tokens: allow the customer to propose a slot w/ duration
ALTER TABLE public.appointment_response_tokens
  ADD COLUMN IF NOT EXISTS requested_start_at timestamptz,
  ADD COLUMN IF NOT EXISTS requested_end_at   timestamptz;

-- ============================================================
-- 038_call_briefs.sql
-- ============================================================
-- Migration 038: Brief timeline (append, not overwrite) + reliable call matching.
--
-- Applied MANUALLY via the Supabase SQL editor (do not `supabase db push`).
-- Additive + idempotent. Safe to re-run.
--
-- PROBLEM this fixes:
--  (a) Today exactly ONE brief lives in communications.summary, and the recording
--      pipeline OVERWRITES it (metadata brief -> transcript brief). Per-call history
--      is lost, so a customer's "journey across calls" cannot be shown.
--  (b) The Twilio RecordingStatusCallback matches the call by a fragile
--      LIKE '%twilio_sid=<CallSid>%' scan of communications.summary, which is never
--      stamped -> recordings silently fail to attach (briefs dropped).
--
-- FIX: a dedicated append-only public.call_briefs table (one row per brief, kept
-- forever) + communications.provider_call_id for exact matching + a synthesized
-- cross-call narrative on customers (journey_summary, written review-first).

-- 1. call_briefs (append-only; one row per brief) -----------------------------
CREATE TABLE IF NOT EXISTS public.call_briefs (
  id               uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  business_id      uuid        NOT NULL REFERENCES public.businesses(id) ON DELETE CASCADE,
  customer_id      uuid        REFERENCES public.customers(id) ON DELETE SET NULL,
  communication_id uuid        REFERENCES public.communications(id) ON DELETE CASCADE,
  brief_kind       text        NOT NULL,
  brief_text       text        NOT NULL,
  created_at       timestamptz NOT NULL DEFAULT now(),

  CONSTRAINT call_briefs_kind_check CHECK (brief_kind IN ('metadata', 'transcript'))
);

CREATE INDEX IF NOT EXISTS call_briefs_business_customer_idx
  ON public.call_briefs (business_id, customer_id, created_at DESC);

CREATE INDEX IF NOT EXISTS call_briefs_communication_idx
  ON public.call_briefs (communication_id);

-- 2. communications.provider_call_id (exact Twilio/PBX call-id match) ----------
ALTER TABLE public.communications
  ADD COLUMN IF NOT EXISTS provider_call_id text;

CREATE INDEX IF NOT EXISTS communications_business_provider_call_idx
  ON public.communications (business_id, provider_call_id)
  WHERE provider_call_id IS NOT NULL;

-- 3. customers: AI-synthesized cross-call narrative (review-first) -------------
ALTER TABLE public.customers
  ADD COLUMN IF NOT EXISTS journey_summary     text,
  ADD COLUMN IF NOT EXISTS journey_updated_at  timestamptz;

-- 4. RLS (mirror the customers/tasks membership pattern from 003_crm_core) -----
ALTER TABLE public.call_briefs ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "call_briefs_select_business_members" ON public.call_briefs;
CREATE POLICY "call_briefs_select_business_members"
  ON public.call_briefs FOR SELECT TO authenticated
  USING (business_id IN (SELECT bu.business_id FROM public.business_users bu WHERE bu.user_id = auth.uid()));

DROP POLICY IF EXISTS "call_briefs_insert_business_members" ON public.call_briefs;
CREATE POLICY "call_briefs_insert_business_members"
  ON public.call_briefs FOR INSERT TO authenticated
  WITH CHECK (business_id IN (SELECT bu.business_id FROM public.business_users bu WHERE bu.user_id = auth.uid()));

-- 5. Grants -------------------------------------------------------------------
GRANT SELECT, INSERT ON public.call_briefs TO authenticated;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.call_briefs TO service_role;

-- ============================================================
-- 039_status_simplify.sql
-- ============================================================
-- Migration 039: Simplify customer status lifecycle (7 -> 4).
--
-- Applied MANUALLY via the Supabase SQL editor (do not `supabase db push`).
-- Idempotent: maps legacy data first, then swaps the CHECK constraint.
--
-- Old set (003_crm_core): new_lead | contacted | follow_up_needed | offer_drafted
--                         | offer_sent | won | lost
-- New set:                new | in_progress | won | lost
-- Mapping: new_lead -> new ; (contacted, follow_up_needed, offer_drafted, offer_sent) -> in_progress
--
-- MUST be applied together with the lockstep code change (CustomerStatus union,
-- labels, API VALID_STATUSES, AI schema/prompt, status writers). The app writes the
-- new values; this constraint rejects the old ones.

-- 1. Drop the OLD CHECK first. The remaps below write 'new'/'in_progress', which
--    the old constraint does not allow yet — so it must be dropped before them.
ALTER TABLE public.customers
  DROP CONSTRAINT IF EXISTS customers_status_check;

-- 2. Map existing rows to the new vocabulary.
UPDATE public.customers SET status = 'in_progress'
 WHERE status IN ('contacted', 'follow_up_needed', 'offer_drafted', 'offer_sent');

UPDATE public.customers SET status = 'new'
 WHERE status = 'new_lead';

-- 3. Add the new CHECK (same name -> the whole file stays re-runnable).
ALTER TABLE public.customers
  ADD CONSTRAINT customers_status_check
    CHECK (status IN ('new', 'in_progress', 'won', 'lost'));

-- 4. Default for brand-new customers.
ALTER TABLE public.customers
  ALTER COLUMN status SET DEFAULT 'new';

-- ============================================================
-- 040_service_catalog.sql
-- ============================================================
-- Migration 040: Service / product catalog (team-shared) + offer line-item link.
--
-- Applied MANUALLY via the Supabase SQL editor (do not `supabase db push`).
-- Additive + idempotent. Safe to re-run.
--
-- New feature: each business keeps a shared catalog of services/products (code,
-- name, price, VAT). The catalog feeds offer building — by voice (AI assistant)
-- or as auto-suggestions when typing a line item manually. Shared across the team
-- (business_users membership), so any member sends offers from the same price list.
--
-- offer_items gains an optional catalog_item_id reference. SNAPSHOT RULE (enforced
-- in the API, not the DB): name/unit_price are copied into the offer_item at
-- creation time, so later catalog price edits never change historical offers.

-- 1. service_catalog_items ----------------------------------------------------
CREATE TABLE IF NOT EXISTS public.service_catalog_items (
  id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  business_id uuid        NOT NULL REFERENCES public.businesses(id) ON DELETE CASCADE,
  code        text,
  name        text        NOT NULL,
  description text,
  category    text,
  unit        text,                      -- e.g. τεμ. / ώρα / m²
  unit_price  numeric     NOT NULL DEFAULT 0,
  vat_rate    numeric     NOT NULL DEFAULT 24,
  active      boolean     NOT NULL DEFAULT true,
  source      text        NOT NULL DEFAULT 'manual',
  created_by  uuid        REFERENCES auth.users(id) ON DELETE SET NULL,
  created_at  timestamptz NOT NULL DEFAULT now(),
  updated_at  timestamptz NOT NULL DEFAULT now(),

  CONSTRAINT service_catalog_unit_price_nonneg CHECK (unit_price >= 0),
  CONSTRAINT service_catalog_vat_rate_nonneg   CHECK (vat_rate   >= 0),
  CONSTRAINT service_catalog_source_check      CHECK (source IN ('manual', 'ai_chat', 'file_import')),

  -- Required so offer_items can FK on (business_id, id) to enforce tenant safety.
  CONSTRAINT service_catalog_items_business_id_key UNIQUE (business_id, id)
);

-- Unique code per business when a code is provided (case-insensitive).
CREATE UNIQUE INDEX IF NOT EXISTS service_catalog_code_uq
  ON public.service_catalog_items (business_id, lower(code))
  WHERE code IS NOT NULL;

CREATE INDEX IF NOT EXISTS service_catalog_list_idx
  ON public.service_catalog_items (business_id, active, category);

-- 2. offer_items -> catalog link (composite FK = tenant-safe) ------------------
ALTER TABLE public.offer_items
  ADD COLUMN IF NOT EXISTS catalog_item_id uuid;

DO $$ BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.table_constraints
    WHERE constraint_name = 'offer_items_catalog_fk' AND table_schema = 'public' AND table_name = 'offer_items'
  ) THEN
    ALTER TABLE public.offer_items
      ADD CONSTRAINT offer_items_catalog_fk
        FOREIGN KEY (business_id, catalog_item_id)
        REFERENCES public.service_catalog_items(business_id, id)
        ON DELETE SET NULL;
  END IF;
END $$;

-- 3. RLS (mirror offers membership pattern from 007_offers_core) ---------------
ALTER TABLE public.service_catalog_items ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "service_catalog_select_business_members" ON public.service_catalog_items;
CREATE POLICY "service_catalog_select_business_members"
  ON public.service_catalog_items FOR SELECT TO authenticated
  USING (business_id IN (SELECT bu.business_id FROM public.business_users bu WHERE bu.user_id = auth.uid()));

DROP POLICY IF EXISTS "service_catalog_insert_business_members" ON public.service_catalog_items;
CREATE POLICY "service_catalog_insert_business_members"
  ON public.service_catalog_items FOR INSERT TO authenticated
  WITH CHECK (business_id IN (SELECT bu.business_id FROM public.business_users bu WHERE bu.user_id = auth.uid()));

DROP POLICY IF EXISTS "service_catalog_update_business_members" ON public.service_catalog_items;
CREATE POLICY "service_catalog_update_business_members"
  ON public.service_catalog_items FOR UPDATE TO authenticated
  USING (business_id IN (SELECT bu.business_id FROM public.business_users bu WHERE bu.user_id = auth.uid()))
  WITH CHECK (business_id IN (SELECT bu.business_id FROM public.business_users bu WHERE bu.user_id = auth.uid()));

-- DELETE intentionally omitted — soft-delete via active=false.

-- 4. Grants -------------------------------------------------------------------
GRANT SELECT, INSERT, UPDATE ON public.service_catalog_items TO authenticated;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.service_catalog_items TO service_role;

-- ============================================================
-- 041_suggested_actions.sql
-- ============================================================
-- Migration 041: AI suggested-action chips (persisted, per customer).
--
-- Applied MANUALLY via the Supabase SQL editor (do not `supabase db push`).
-- Additive + idempotent. Safe to re-run.
--
-- The redesign shows AI-proposed next actions as tappable chips inside the
-- customer chat (e.g. after a call: "Δημιουργία προσφοράς"). Today the "next
-- action" lives only as free-text inside communications.summary and the /api/ai
-- intents are ephemeral. This table persists those suggestions so they can be
-- rendered, acted on, or dismissed — and is the single append-only point that the
-- chat can subscribe to for live updates.

CREATE TABLE IF NOT EXISTS public.suggested_actions (
  id                      uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  business_id             uuid        NOT NULL REFERENCES public.businesses(id) ON DELETE CASCADE,
  customer_id             uuid        NOT NULL REFERENCES public.customers(id) ON DELETE CASCADE,
  source_communication_id uuid        REFERENCES public.communications(id) ON DELETE SET NULL,
  action_type             text        NOT NULL,
  label                   text        NOT NULL,
  params                  jsonb,
  status                  text        NOT NULL DEFAULT 'pending',
  created_at              timestamptz NOT NULL DEFAULT now(),

  CONSTRAINT suggested_actions_type_check CHECK (action_type IN (
    'send_offer', 'book_appointment', 'call_back',
    'request_photos', 'request_details', 'reminder'
  )),
  CONSTRAINT suggested_actions_status_check CHECK (status IN ('pending', 'done', 'dismissed'))
);

CREATE INDEX IF NOT EXISTS suggested_actions_open_idx
  ON public.suggested_actions (business_id, customer_id, status, created_at DESC);

-- RLS (membership pattern) ----------------------------------------------------
ALTER TABLE public.suggested_actions ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "suggested_actions_select_business_members" ON public.suggested_actions;
CREATE POLICY "suggested_actions_select_business_members"
  ON public.suggested_actions FOR SELECT TO authenticated
  USING (business_id IN (SELECT bu.business_id FROM public.business_users bu WHERE bu.user_id = auth.uid()));

DROP POLICY IF EXISTS "suggested_actions_insert_business_members" ON public.suggested_actions;
CREATE POLICY "suggested_actions_insert_business_members"
  ON public.suggested_actions FOR INSERT TO authenticated
  WITH CHECK (business_id IN (SELECT bu.business_id FROM public.business_users bu WHERE bu.user_id = auth.uid()));

DROP POLICY IF EXISTS "suggested_actions_update_business_members" ON public.suggested_actions;
CREATE POLICY "suggested_actions_update_business_members"
  ON public.suggested_actions FOR UPDATE TO authenticated
  USING (business_id IN (SELECT bu.business_id FROM public.business_users bu WHERE bu.user_id = auth.uid()))
  WITH CHECK (business_id IN (SELECT bu.business_id FROM public.business_users bu WHERE bu.user_id = auth.uid()));

GRANT SELECT, INSERT, UPDATE ON public.suggested_actions TO authenticated;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.suggested_actions TO service_role;

-- ============================================================
-- 042_preferred_channel_tighten.sql
-- ============================================================
-- Migration 042: Drop WhatsApp from the preferred contact channel set.
--
-- Applied MANUALLY via the Supabase SQL editor (do not `supabase db push`).
-- Idempotent: remaps existing 'whatsapp' rows first, then tightens the CHECK.
--
-- The redesign's communication waterfall is: mobile -> Viber (auto-fallback to SMS),
-- landline -> Email. WhatsApp is removed as a channel. 035 had widened the set to
-- include 'whatsapp' and 'sms'; this narrows it back to ('viber','sms','email','phone').

-- 1. Remap any existing whatsapp preference to viber (the mobile default channel).
UPDATE public.customers SET preferred_contact_method = 'viber'
 WHERE preferred_contact_method = 'whatsapp';

-- 2. Tighten the CHECK (drop-then-add keeps the same name -> re-runnable).
ALTER TABLE public.customers
  DROP CONSTRAINT IF EXISTS customers_preferred_contact_method_check;

ALTER TABLE public.customers
  ADD CONSTRAINT customers_preferred_contact_method_check
    CHECK (preferred_contact_method IN ('viber', 'sms', 'email', 'phone'));

-- ============================================================
-- 043_review_fixes.sql
-- ============================================================
-- Migration 043: Product-readiness review fixes (sessions 16 — R3/R4/R6).
--
-- Applied MANUALLY via the Supabase SQL editor (do not `supabase db push`).
-- Idempotent: constraint swaps use DROP IF EXISTS + ADD, columns/indexes use
-- IF NOT EXISTS, functions use CREATE OR REPLACE.
--
-- Contents:
--   1. communications.status: allow 'missed' (the missed-call funnel writes it;
--      web/native already render it — the constraint was the only blocker).
--   2. provider_webhook_events.provider: allow 'twilio' (recording reconcile
--      queue for the brief pipeline).
--   3. Atomic per-business counters for crm_number / offer_number — replaces
--      the O(n) fetch-all-and-Math.max scan and closes the duplicate-number
--      race. Backfilled from the current maxima.
--   4. Indexes: communications(provider_call_id) for the recording webhook's
--      lookup (038's index leads with business_id, which that lookup lacks),
--      and (business_id, responded_at DESC) on the two response-token tables
--      used by the notifications bell on every dashboard render.

-- 1. communications.status += 'missed' ---------------------------------------
ALTER TABLE public.communications
  DROP CONSTRAINT IF EXISTS communications_status_check;

ALTER TABLE public.communications
  ADD CONSTRAINT communications_status_check
    CHECK (status IN ('started', 'sent', 'delivered', 'seen', 'failed', 'completed', 'missed'));

-- 2. provider_webhook_events.provider += 'twilio' -----------------------------
ALTER TABLE public.provider_webhook_events
  DROP CONSTRAINT IF EXISTS provider_webhook_events_provider_check;

ALTER TABLE public.provider_webhook_events
  ADD CONSTRAINT provider_webhook_events_provider_check
    CHECK (provider IN ('apifon', 'telnyx', 'pbx', 'twilio'));

-- 3. Atomic counters ----------------------------------------------------------
ALTER TABLE public.businesses
  ADD COLUMN IF NOT EXISTS next_crm_number integer,
  ADD COLUMN IF NOT EXISTS next_offer_number integer;

-- Backfill from the current maxima (same trailing-digits rule the app used).
UPDATE public.businesses b
   SET next_crm_number = COALESCE(
     (SELECT MAX((substring(c.crm_number FROM '(\d+)\s*$'))::int) + 1
        FROM public.customers c
       WHERE c.business_id = b.id
         AND c.crm_number ~ '\d+\s*$'),
     1)
 WHERE b.next_crm_number IS NULL;

UPDATE public.businesses b
   SET next_offer_number = COALESCE(
     (SELECT MAX((substring(o.offer_number FROM '(\d+)\s*$'))::int) + 1
        FROM public.offers o
       WHERE o.business_id = b.id
         AND o.offer_number ~ '\d+\s*$'),
     1)
 WHERE b.next_offer_number IS NULL;

-- Atomic take-a-number. UPDATE ... RETURNING is atomic per row, so two
-- concurrent calls can never mint the same number.
CREATE OR REPLACE FUNCTION public.take_next_crm_number(p_business_id uuid)
RETURNS integer
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
AS $$
  UPDATE public.businesses
     SET next_crm_number = COALESCE(next_crm_number, 1) + 1
   WHERE id = p_business_id
   RETURNING next_crm_number - 1;
$$;

CREATE OR REPLACE FUNCTION public.take_next_offer_number(p_business_id uuid)
RETURNS integer
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
AS $$
  UPDATE public.businesses
     SET next_offer_number = COALESCE(next_offer_number, 1) + 1
   WHERE id = p_business_id
   RETURNING next_offer_number - 1;
$$;

-- Service-role only (the API routes call these; clients never do).
REVOKE ALL ON FUNCTION public.take_next_crm_number(uuid) FROM PUBLIC;
REVOKE ALL ON FUNCTION public.take_next_crm_number(uuid) FROM anon;
REVOKE ALL ON FUNCTION public.take_next_crm_number(uuid) FROM authenticated;
GRANT EXECUTE ON FUNCTION public.take_next_crm_number(uuid) TO service_role;

REVOKE ALL ON FUNCTION public.take_next_offer_number(uuid) FROM PUBLIC;
REVOKE ALL ON FUNCTION public.take_next_offer_number(uuid) FROM anon;
REVOKE ALL ON FUNCTION public.take_next_offer_number(uuid) FROM authenticated;
GRANT EXECUTE ON FUNCTION public.take_next_offer_number(uuid) TO service_role;

-- 4. Indexes -------------------------------------------------------------------
CREATE INDEX IF NOT EXISTS communications_provider_call_idx
  ON public.communications (provider_call_id)
  WHERE provider_call_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS offer_response_tokens_business_responded_idx
  ON public.offer_response_tokens (business_id, responded_at DESC);

CREATE INDEX IF NOT EXISTS appointment_response_tokens_business_responded_idx
  ON public.appointment_response_tokens (business_id, responded_at DESC);

