-- transcodes to 8 kHz mono PCM WAV per business, and the dialplan plays it (via an
-- OPIFLOW_DISCLOSURE channel var) BEFORE bridging — falling back to the global
-- opiflow-call-recorded clip when a business has not recorded one. App code is
-- TOLERANT of this column being absent (the /api/businesses/me/disclosure-audio
-- route degrades to "not configured"), so this is safe to ship before the SQL lands.
--
-- No RLS change: the businesses UPDATE policy (migration 022) already covers it,
-- and all writes go through the service-role server route.

ALTER TABLE public.businesses
  ADD COLUMN IF NOT EXISTS recording_disclosure_audio text;

-- ============================================================
-- 056_grant_service_role_on_payments.sql
-- ============================================================
-- Corrective service_role grants for migration 048 (payment_requests).
--
-- Migration 048 created public.payment_requests (+ enabled RLS) but, exactly like
-- the activation tables fixed in migration 021, omitted explicit GRANT statements.
-- service_role bypasses RLS, but PostgreSQL still denies table access at the
-- privilege level BEFORE RLS is evaluated — so without a GRANT the server-side
-- payment routes (createServiceSupabaseClient) can receive a permission-denied
-- error when reading/writing payment_requests (owner confirm/cancel, the public
-- portal «Δήλωσα την κατάθεση», the folder payment lists).
--
-- Adds the minimum required grant:
--   service_role: SELECT, INSERT, UPDATE on payment_requests.
--     Used by all server-side payment API routes.
--     DELETE is intentionally NOT granted (consistent with migration 021); the
--     app cancels a request via UPDATE (status = 'cancelled'), never a hard delete.
--
-- No table is altered. No RLS policy is modified. No anon/authenticated grant is
-- added (payments are server-only; the public portal reads them through a
-- service_role route gated by the folder token, not via an authenticated policy).
-- GRANT is idempotent in PostgreSQL — this migration is safe to re-run.

GRANT SELECT, INSERT, UPDATE ON public.payment_requests TO service_role;

-- ============================================================
-- 057_portal_read_receipts.sql
-- ============================================================
-- 057_portal_read_receipts.sql
--
-- Read receipts for owner→customer messages shown in the public shared-link
-- portal, plus a rolling "last visited" timestamp on the folder token used by
-- the 24h unread-message reminder cron.
--
-- Idempotent (ADD COLUMN IF NOT EXISTS / CREATE INDEX IF NOT EXISTS) so it is
-- safe to re-run. Apply MANUALLY in the Supabase SQL editor (live project).
--
-- All reads/writes of these columns in the app are TOLERANT: until this
-- migration is applied, read receipts simply don't show and the unread cron
-- no-ops — nothing breaks.

-- When the customer opens the chat thread in the portal, the owner's outbound
-- messages for that folder get read_at = now().
alter table public.communications
  add column if not exists read_at timestamptz;

-- Rolled forward each time the customer views the portal chat. Lets the cron
-- tell "never opened / not opened recently" apart from "just looked".
alter table public.customer_folder_tokens
  add column if not exists last_visited_at timestamptz;

-- Fast "unread outbound messages in this folder" lookups for the reminder cron.
create index if not exists communications_unread_outbound_idx
  on public.communications (business_id, work_folder_id)
  where read_at is null and direction = 'outbound';

