-- 060_business_exempt_numbers.sql
-- ============================================================
-- Migration 060 — per-business call EXEMPTION list (#9).
-- Apply manually via the Supabase SQL editor (live project oluhmztfimmgmbxoioea).
--
-- Numbers in this list are EXEMPT from BOTH the «η κλήση ηχογραφείται» disclosure
-- AND from recording — the owner's personal contacts (friends/family) who call the
-- same number they use for business and must not be recorded. Decoupled from
-- `customers` on purpose: exempting personal contacts must NOT turn them into CRM
-- customers. `phone` holds the last-10 normalized digits for format-tolerant matching
-- (same scheme as the blocked-caller + customer phone matching elsewhere).
--
-- The API layer and the call path are TOLERANT of this table being absent (it
-- degrades to "no exemptions") so nothing breaks before the migration is applied.

CREATE TABLE IF NOT EXISTS public.business_exempt_numbers (
  id          uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  business_id uuid NOT NULL REFERENCES public.businesses(id) ON DELETE CASCADE,
  phone       text NOT NULL,
  label       text,
  created_at  timestamptz NOT NULL DEFAULT now()
);

-- One row per (business, number); also the fast "is this caller exempt?" lookup.
CREATE UNIQUE INDEX IF NOT EXISTS business_exempt_numbers_biz_phone_idx
  ON public.business_exempt_numbers (business_id, phone);

-- ============================================================
-- 061_self_serve_billing.sql
-- ============================================================
-- 061: Self-serve monetization — pay-at-signup entitlement model + Stripe linkage
--
-- Enables the pay-immediately-at-signup flow:
--   * New public signups get status 'pending_payment' (NOT entitled) and must
--     complete Stripe Checkout before using the product. The Stripe webhook flips
--     them to 'active'.
--   * 'past_due' supports dunning (a failed renewal) without an immediate cancel.
--   * Existing manual/pilot accounts ('pending_manual_review'/'trialing') are
--     UNCHANGED and stay entitled — see src/lib/billing/entitlement.ts.
--
-- The application code degrades gracefully until this migration is applied: a
-- signup that can't write 'pending_payment' (CHECK violation) falls back to the
-- legacy 'pending_manual_review', so the product keeps working pre-migration.
--
-- Idempotent / safe to re-run.

-- 1) Dedicated Stripe id columns (billing_provider/billing_ref already exist from
--    017; these make the linkage explicit for the billing portal + reconciliation).
ALTER TABLE public.business_subscriptions
  ADD COLUMN IF NOT EXISTS stripe_customer_id     text,
  ADD COLUMN IF NOT EXISTS stripe_subscription_id text;

-- 2) Extend the status CHECK with the two new states.
ALTER TABLE public.business_subscriptions
  DROP CONSTRAINT IF EXISTS business_subscriptions_status_check;

ALTER TABLE public.business_subscriptions
  ADD CONSTRAINT business_subscriptions_status_check
  CHECK (status IN (
    'pending_manual_review',
    'pending_payment',
    'trialing',
    'active',
    'past_due',
    'cancelled'
  ));

-- ============================================================
-- 062_customer_phone_indexes.sql
-- ============================================================
-- 062: Index the inbound caller→customer lookup (audit P2-4).
--
-- Every inbound call (PBX webhook + in-app calls/log) resolves the caller with
--   .or('phone.eq.<n>,mobile_phone.eq.<n>,landline_phone.eq.<n>')  scoped by business_id.
-- Migration 027 indexed customers(business_id) and (business_id, created_at) but
-- NONE of the three phone columns, so that lookup is a seq-scan per inbound call —
-- the slowest part of the call-logging hot path on a tenant with many customers.
--
-- These composite (business_id, <phone column>) indexes make each branch of the
-- .or() an index lookup. Additive + idempotent; CONCURRENTLY is omitted because
-- the Supabase SQL editor runs in a transaction (plain CREATE INDEX is fine at
-- this scale — the tables are small today).

CREATE INDEX IF NOT EXISTS customers_business_phone_idx
  ON public.customers (business_id, phone);

CREATE INDEX IF NOT EXISTS customers_business_mobile_phone_idx
  ON public.customers (business_id, mobile_phone);

CREATE INDEX IF NOT EXISTS customers_business_landline_phone_idx
  ON public.customers (business_id, landline_phone);

-- ============================================================
-- 063_outbox_events.sql
-- ============================================================
-- Opiflow Outbox (transactional outbound delivery)
-- Backs the Outbox pattern for OUTBOUND side-effects (Viber/SMS/email/webhooks):
-- record the intent first, then a worker delivers it with retries + idempotency,
-- so a provider hiccup never loses a message and a retried send is never doubled.
-- See docs/ARCHITECTURE_REFACTOR_PLAN.md (point #7) and src/server/outbox/.
--
-- NOT YET WIRED to any worker; this migration only provisions the schema. Rows are
-- written/claimed exclusively by server-side code using the service role. RLS is
-- enabled with NO public policies (service role bypasses RLS), consistent with
-- jobs (030), provider_webhook_events (003), and audit_events (029).
--
-- Idempotent: CREATE TABLE/INDEX IF NOT EXISTS. business_id is nullable (system
-- events). dedup_key is an optional caller-supplied idempotency key; a partial
-- UNIQUE index makes a second record() with the same (business_id, dedup_key) a
-- no-op so retries/double-submits collapse to one delivery. updated_at is managed
-- by the app/worker layer, not a trigger (consistent with the rest of the schema).

CREATE TABLE IF NOT EXISTS public.outbox_events (
  id            uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  business_id   uuid,
  kind          text        NOT NULL,          -- 'viber' | 'sms' | 'email' | 'webhook' | ...
  dedup_key     text,                          -- optional idempotency key
  payload       jsonb       NOT NULL,
  status        text        NOT NULL DEFAULT 'pending', -- pending|processing|sent|failed
  attempts      integer     NOT NULL DEFAULT 0,
  next_retry_at timestamptz NOT NULL DEFAULT now(),
  last_error    text,
  sent_at       timestamptz,
  created_at    timestamptz NOT NULL DEFAULT now(),
  updated_at    timestamptz NOT NULL DEFAULT now()
);

-- Worker dispatch index: find due pending events ordered by next_retry_at.
CREATE INDEX IF NOT EXISTS outbox_events_status_retry_idx
  ON public.outbox_events (status, next_retry_at);

-- Idempotency: at most one event per (business_id, dedup_key) when a key is given.
CREATE UNIQUE INDEX IF NOT EXISTS outbox_events_business_dedup_uidx
  ON public.outbox_events (business_id, dedup_key)
  WHERE dedup_key IS NOT NULL;

-- ---------------------------------------------------------------------------
-- Row Level Security: enabled, no public policies. Service role only.
-- ---------------------------------------------------------------------------
ALTER TABLE public.outbox_events ENABLE ROW LEVEL SECURITY;

REVOKE ALL PRIVILEGES ON TABLE public.outbox_events FROM anon;
REVOKE ALL PRIVILEGES ON TABLE public.outbox_events FROM authenticated;
REVOKE ALL PRIVILEGES ON TABLE public.outbox_events FROM service_role;

GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.outbox_events TO service_role;
